import React, { useState, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { api } from '../../contexts/AuthContext';
import ConfirmDialog from '../../components/ConfirmDialog';

const AdminVideos = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const statusFilter = searchParams.get('status') || 'all';

  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedVideos, setSelectedVideos] = useState([]);
  const [editingVideo, setEditingVideo] = useState(null);
  const [confirmDialog, setConfirmDialog] = useState({
    isOpen: false,
    type: 'danger',
    title: '',
    message: '',
    onConfirm: null
  });
  const [hoveredVideo, setHoveredVideo] = useState(null);

  useEffect(() => {
    fetchVideos();
  }, [statusFilter, currentPage, searchQuery]);

  const fetchVideos = async () => {
    setLoading(true);
    try {
      const response = await api.get('/admin/videos', {
        params: {
          status: statusFilter,
          page: currentPage,
          per_page: 20,
          search: searchQuery
        }
      });
      setVideos(response.data.videos);
      setTotalPages(response.data.pages);
      setSelectedVideos([]);
    } catch (error) {
      console.error('Error fetching videos:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatDuration = (seconds) => {
    if (!seconds) return '00:00';
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const formatViews = (views) => {
    if (views >= 1000000) {
      return `${(views / 1000000).toFixed(1)}M`;
    } else if (views >= 1000) {
      return `${(views / 1000).toFixed(1)}K`;
    }
    return views.toString();
  };

  const handleSearch = (e) => {
    e.preventDefault();
    setCurrentPage(1);
    fetchVideos();
  };

  const handleStatusChange = (status) => {
    setSearchParams({ status });
    setCurrentPage(1);
  };

  const toggleSelectVideo = (videoId) => {
    setSelectedVideos(prev =>
      prev.includes(videoId)
        ? prev.filter(id => id !== videoId)
        : [...prev, videoId]
    );
  };

  const toggleSelectAll = () => {
    setSelectedVideos(
      selectedVideos.length === videos.length
        ? []
        : videos.map(v => v.id)
    );
  };

  const bulkUpdateStatus = async (status) => {
    if (selectedVideos.length === 0) return;

    try {
      await api.post('/admin/videos/bulk-update', {
        video_ids: selectedVideos,
        status
      });
      fetchVideos();
    } catch (error) {
      console.error('Error updating videos:', error);
      alert('操作失败，请重试');
    }
  };

  const bulkDelete = () => {
    if (selectedVideos.length === 0) return;

    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '批量删除视频',
      message: `确定要删除选中的 ${selectedVideos.length} 个视频吗？此操作不可撤销。`,
      onConfirm: async () => {
        try {
          await api.post('/admin/videos/bulk-delete', {
            video_ids: selectedVideos
          });
          fetchVideos();
        } catch (error) {
          console.error('Error deleting videos:', error);
          alert('删除失败，请重试');
        }
        setConfirmDialog({ ...confirmDialog, isOpen: false });
      }
    });
  };

  const deleteVideo = (videoId) => {
    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '删除视频',
      message: '确定要删除这个视频吗？此操作不可撤销。',
      onConfirm: async () => {
        try {
          await api.delete(`/admin/videos/${videoId}`);
          fetchVideos();
        } catch (error) {
          console.error('Error deleting video:', error);
          alert('删除失败，请重试');
        }
        setConfirmDialog({ ...confirmDialog, isOpen: false });
      }
    });
  };

  const updateVideo = async (videoId, data) => {
    try {
      await api.put(`/admin/videos/${videoId}`, data);
      setEditingVideo(null);
      fetchVideos();
    } catch (error) {
      console.error('Error updating video:', error);
      alert('更新失败，请重试');
    }
  };

  const getStatusBadge = (status) => {
    const styles = {
      pending: 'bg-yellow-100 text-yellow-800',
      approved: 'bg-green-100 text-green-800',
      rejected: 'bg-red-100 text-red-800'
    };

    const labels = {
      pending: '待审核',
      approved: '已通过',
      rejected: '已拒绝'
    };

    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${styles[status] || 'bg-gray-100 text-gray-800'}`}>
        {labels[status] || status}
      </span>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">视频管理</h1>
            <p className="text-gray-600 mt-1">管理平台所有视频内容</p>
          </div>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-xl shadow-sm p-4 mb-6">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between space-y-4 md:space-y-0">
            {/* Status Tabs */}
            <div className="flex space-x-1">
              {[
                { id: 'all', label: '全部' },
                { id: 'pending', label: '待审核' },
                { id: 'approved', label: '已通过' },
                { id: 'rejected', label: '已拒绝' }
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => handleStatusChange(tab.id)}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                    statusFilter === tab.id
                      ? 'bg-primary-600 text-white'
                      : 'text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>

            {/* Search */}
            <form onSubmit={handleSearch} className="flex space-x-2">
              <input
                type="text"
                placeholder="搜索视频标题、作者..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="flex-1 border border-gray-300 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary-500"
              />
              <button
                type="submit"
                className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg text-sm hover:bg-gray-200 transition-colors"
              >
                搜索
              </button>
              {videos.length > 0 && (
                <button
                  type="button"
                  onClick={toggleSelectAll}
                  className="bg-primary-100 text-primary-700 px-4 py-2 rounded-lg text-sm hover:bg-primary-200 transition-colors"
                >
                  {selectedVideos.length === videos.length ? '取消全选' : '全选'}
                </button>
              )}
            </form>
          </div>
        </div>

        {/* Bulk Actions */}
        {selectedVideos.length > 0 && (
          <div className="bg-primary-50 border border-primary-200 rounded-lg p-4 mb-6">
            <div className="flex items-center justify-between">
              <span className="text-primary-800 font-medium">
                已选择 {selectedVideos.length} 个视频
              </span>
              <div className="flex space-x-2">
                <button
                  onClick={() => bulkUpdateStatus('approved')}
                  className="bg-green-600 text-white px-3 py-1.5 rounded text-sm hover:bg-green-700 transition-colors"
                >
                  批量通过
                </button>
                <button
                  onClick={() => bulkUpdateStatus('rejected')}
                  className="bg-red-600 text-white px-3 py-1.5 rounded text-sm hover:bg-red-700 transition-colors"
                >
                  批量拒绝
                </button>
                <button
                  onClick={bulkDelete}
                  className="bg-gray-600 text-white px-3 py-1.5 rounded text-sm hover:bg-gray-700 transition-colors"
                >
                  批量删除
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Videos Table */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
          {loading ? (
            <div className="p-8">
              <div className="animate-pulse space-y-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="flex items-center space-x-4">
                    <div className="w-24 h-16 bg-gray-200 rounded"></div>
                    <div className="flex-1 space-y-2">
                      <div className="h-4 bg-gray-200 rounded w-1/4"></div>
                      <div className="h-3 bg-gray-200 rounded w-1/6"></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : videos.length > 0 ? (
            <div className="space-y-4">
              {videos.map((video) => (
                <div key={video.id} className="bg-white rounded-lg border border-gray-200 hover:border-gray-300 hover:shadow-sm transition-all">
                  <div className="flex flex-col sm:flex-row">
                    {/* Thumbnail */}
                    <div className="sm:w-64 sm:flex-shrink-0">
                      <div className="relative">
                        {/* Checkbox for bulk selection */}
                        <div className="absolute top-3 left-3 z-10">
                          <input
                            type="checkbox"
                            checked={selectedVideos.includes(video.id)}
                            onChange={() => toggleSelectVideo(video.id)}
                            className="rounded border-gray-300 bg-white/90 backdrop-blur-sm"
                          />
                        </div>

                        <Link to={`/video/${video.id}`} target="_blank" className="block">
                          <div className="relative aspect-video bg-gray-900 overflow-hidden rounded-t-lg sm:rounded-l-lg sm:rounded-tr-none">
                            <div 
                              className="w-full h-full"
                              onMouseEnter={() => setHoveredVideo(video.id)}
                              onMouseLeave={() => setHoveredVideo(null)}
                            >
                              {hoveredVideo === video.id ? (
                                <video
                                  src={`http://localhost:5000/api/video/stream/${video.id}`}
                                  autoPlay
                                  muted
                                  loop
                                  className="w-full h-full object-cover"
                                />
                              ) : video.cover_image ? (
                                <img
                                  src={`http://localhost:5000/api/video/cover/${video.id}`}
                                  alt={video.title}
                                  className="w-full h-full object-cover"
                                />
                              ) : (
                                <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                                  <svg className="w-8 h-8 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                                    <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                                  </svg>
                                </div>
                              )}
                            </div>

                            {/* Status Badge */}
                            <div className="absolute top-3 right-3">
                              {getStatusBadge(video.status)}
                            </div>

                            {/* Duration Badge */}
                            <div className="absolute bottom-3 right-3 bg-black/70 text-white text-xs px-2 py-1 rounded">
                              {formatDuration(video.duration)}
                            </div>
                          </div>
                        </Link>
                      </div>
                    </div>

                    {/* Content */}
                    <div className="flex-1 p-4 sm:p-6">
                      <div className="flex items-start justify-between mb-3">
                        <div className="flex-1 min-w-0">
                          <h3 className="text-lg font-semibold text-gray-900 mb-2 hover:text-primary-600 transition-colors">
                            <Link 
                              to={`/video/${video.id}`}
                              target="_blank"
                              className="hover:text-primary-600 transition-colors"
                            >
                              {video.title}
                            </Link>
                          </h3>

                          <p className="text-sm text-gray-600 mb-3 line-clamp-2">
                            {video.description || '暂无简介'}
                          </p>

                          {/* Video Metadata */}
                          <div className="flex flex-wrap items-center gap-4 text-sm text-gray-500 mb-4">
                            <div className="flex items-center space-x-1">
                              <div className="w-6 h-6 bg-gray-200 rounded-full flex items-center justify-center">
                                <svg className="w-3 h-3 text-gray-600" fill="currentColor" viewBox="0 0 20 20">
                                  <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                                </svg>
                              </div>
                              <span className="font-medium">{video.author}</span>
                            </div>

                            <div className="flex items-center space-x-1">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                              </svg>
                              <span>{formatViews(video.view_count)} 次播放</span>
                            </div>

                            <div className="flex items-center space-x-1">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                              </svg>
                              <span>{new Date(video.created_at).toLocaleDateString()}</span>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* Actions */}
                      <div className="flex items-center space-x-2 border-t pt-4">
                        {video.status === 'pending' && (
                          <>
                            <button
                              onClick={() => updateVideoStatus(video.id, 'approved')}
                              className="flex-1 bg-green-600 text-white text-center py-2 px-4 rounded-lg hover:bg-green-700 transition-colors text-sm font-medium"
                            >
                              通过审核
                            </button>
                            <button
                              onClick={() => updateVideoStatus(video.id, 'rejected')}
                              className="flex-1 bg-red-600 text-white text-center py-2 px-4 rounded-lg hover:bg-red-700 transition-colors text-sm font-medium"
                            >
                              拒绝视频
                            </button>
                          </>
                        )}

                        <Link
                          to={`/video/${video.id}`}
                          target="_blank"
                          className="flex-1 bg-blue-600 text-white text-center py-2 px-4 rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium"
                        >
                          查看视频
                        </Link>

                        <button
                          onClick={() => setEditingVideo(video)}
                          className="p-2 text-gray-400 hover:text-yellow-600 transition-colors"
                          title="编辑"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                          </svg>
                        </button>

                        <button
                          onClick={() => deleteVideo(video.id)}
                          className="p-2 text-gray-400 hover:text-red-600 transition-colors"
                          title="删除"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16">
              <svg className="w-16 h-16 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 4v16M17 4v16M3 8h4m10 0h4M3 12h18M3 16h4m10 0h4M4 20h16a1 1 0 001-1V5a1 1 0 00-1-1H4a1 1 0 00-1 1v14a1 1 0 001 1z" />
              </svg>
              <p className="text-gray-500">暂无视频</p>
            </div>
          )}
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex justify-center mt-6 space-x-2">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="px-4 py-2 border border-gray-300 rounded-lg disabled:opacity-50 hover:bg-gray-50"
            >
              上一页
            </button>
            <span className="px-4 py-2">
              第 {currentPage} 页，共 {totalPages} 页
            </span>
            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="px-4 py-2 border border-gray-300 rounded-lg disabled:opacity-50 hover:bg-gray-50"
            >
              下一页
            </button>
          </div>
        )}
      </div>

      {/* Edit Modal */}
      {editingVideo && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 w-full max-w-lg mx-4">
            <h2 className="text-lg font-bold mb-4">编辑视频</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">标题</label>
                <input
                  type="text"
                  defaultValue={editingVideo.title}
                  onChange={(e) => editingVideo.title = e.target.value}
                  className="w-full border border-gray-300 rounded-lg px-3 py-2"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">简介</label>
                <textarea
                  defaultValue={editingVideo.description}
                  onChange={(e) => editingVideo.description = e.target.value}
                  rows="3"
                  className="w-full border border-gray-300 rounded-lg px-3 py-2"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">状态</label>
                <select
                  defaultValue={editingVideo.status}
                  onChange={(e) => editingVideo.status = e.target.value}
                  className="w-full border border-gray-300 rounded-lg px-3 py-2"
                >
                  <option value="pending">待审核</option>
                  <option value="approved">已通过</option>
                  <option value="rejected">已拒绝</option>
                </select>
              </div>
            </div>
            <div className="flex justify-end space-x-3 mt-6">
              <button
                onClick={() => setEditingVideo(null)}
                className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                取消
              </button>
              <button
                onClick={() => updateVideo(editingVideo.id, editingVideo)}
                className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700"
              >
                保存
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Confirm Dialog */}
      <ConfirmDialog
        isOpen={confirmDialog.isOpen}
        onClose={() => setConfirmDialog({ ...confirmDialog, isOpen: false })}
        onConfirm={confirmDialog.onConfirm}
        title={confirmDialog.title}
        message={confirmDialog.message}
        type={confirmDialog.type}
        confirmText="确认"
        cancelText="取消"
      />
    </div>
  );
};

export default AdminVideos;
